  "onboarding.intent.lighthouse-watch.briefText": "You're sharpening your visual radar, training your brain to lock onto high-value targets while muting the background noise of distractions.",
  "onboarding.intent.lighthouse-watch.bullet.1.bold": "Target:",
  "onboarding.intent.lighthouse-watch.bullet.1.text": "Tap ONLY when you see the glowing green star.",
  "onboarding.intent.lighthouse-watch.bullet.2.bold": "Focus:",
  "onboarding.intent.lighthouse-watch.bullet.2.text": "Avoid clicking shapes of other colors.",
  "onboarding.intent.lighthouse-watch.bullet.3.bold": "Calibration:",
  "onboarding.intent.lighthouse-watch.bullet.3.text": "Accuracy and speed combine to build your focus score.",
  "onboarding.intent.signal-chain.briefText": "You're stretching your short-term recall capacity, linking spatial nodes in sequential order to build a stronger mental scratchpad.",
  "onboarding.intent.signal-chain.bullet.1.bold": "Pattern:",
  "onboarding.intent.signal-chain.bullet.1.text": "Watch carefully as the nodes pulse in a specific sequence.",
  "onboarding.intent.signal-chain.bullet.2.bold": "Recall:",
  "onboarding.intent.signal-chain.bullet.2.text": "Tap the nodes in the exact same sequence you just saw.",
  "onboarding.intent.signal-chain.bullet.3.bold": "Challenge:",
  "onboarding.intent.signal-chain.bullet.3.text": "The sequence grows longer with each successful round.",
  "onboarding.intent.flash-sort.briefText": "You're accelerating your visual-motor processing speed, training your brain to make lightning-fast sorting decisions under pressure.",
  "onboarding.intent.flash-sort.bullet.1.bold": "Sort:",
  "onboarding.intent.flash-sort.bullet.1.text": "Tap left for circles and right for squares as they appear.",
  "onboarding.intent.flash-sort.bullet.2.bold": "Speed:",
  "onboarding.intent.flash-sort.bullet.2.text": "React as fast as possible to maximize your speed bonus.",
  "onboarding.intent.flash-sort.bullet.3.bold": "Distraction:",
  "onboarding.intent.flash-sort.bullet.3.text": "Ignore changing colors and background stripes.",
  "onboarding.intent.context-switch.briefText": "You're conditioning your cognitive flexibility, training your brain to switch rapidly and smoothly between different classification rules.",
  "onboarding.intent.context-switch.bullet.1.bold": "Rule 1:",
  "onboarding.intent.context-switch.bullet.1.text": "When the border is blue",
  "onboarding.intent.context-switch.bullet.2.bold": "Rule 2:",
  "onboarding.intent.context-switch.bullet.2.text": "When the border is red",
  "onboarding.intent.context-switch.bullet.3.bold": "Agility:",
  "onboarding.intent.context-switch.bullet.3.text": "Adapt quickly as the borders change to minimize switch cost.",
  "onboarding.intent.word-weave.briefText": "You're sharpening your semantic mapping and lexical retrieval, identifying relational patterns between pairs of words.",
  "onboarding.intent.word-weave.bullet.1.bold": "Analogy:",
  "onboarding.intent.word-weave.bullet.1.text": "Identify the relationship between the first pair of words.",
  "onboarding.intent.word-weave.bullet.2.bold": "Solve:",
  "onboarding.intent.word-weave.bullet.2.text": "Select the word that completes the second pair in the same way.",
  "onboarding.intent.word-weave.bullet.3.bold": "Vocabulary:",
  "onboarding.intent.word-weave.bullet.3.text": "Think logically to build your verbal reasoning score.",
  "onboarding.intent.pattern-fold.briefText": "You're training your mental rotation and spatial projection, visualizing how 2D nets fold into 3D objects from different perspectives.",
  "onboarding.intent.pattern-fold.bullet.1.bold": "Visualize:",
  "onboarding.intent.pattern-fold.bullet.1.text": "Look at the target block grid pattern on the left.",
  "onboarding.intent.pattern-fold.bullet.2.bold": "Rotate:",
  "onboarding.intent.pattern-fold.bullet.2.text": "Mentally rotate the pattern to identify the matching choice.",
  "onboarding.intent.pattern-fold.bullet.3.bold": "Chirality:",
  "onboarding.intent.pattern-fold.bullet.3.text": "Watch out for tricky flipped mirror distractors.",
